class Solution {
    public int longestSemiRepetitiveSubstring(String s) {
        int n = s.length();
        int maxLength = 1;
        for (int i = 1; i < n; i++) {
            int count = 1;
            for (int j = i; j < n; j++) {
                if (s.charAt(j) == s.charAt(j - 1)) {
                    count++;
                } else {
                    maxLength = Math.max(maxLength, count);
                    count = 1;
                }
            }
            maxLength = Math.max(maxLength, count);
        }
        return maxLength;
    }
}
```

